 19→/**
 20→ * https://kotlinlang.org/docs/coding-conventions.html#function-names
 21→ * https://kotlinlang.org/docs/coding-conventions.html#property-names
 22→ */
 23→public class PropertyNamingRule : Rule("$EXPERIMENTAL_RULE_SET_ID:property-naming") {
 24→    override fun beforeVisitChildNodes(
 25→        node: ASTNode,
 26→        autoCorrect: Boolean,
 27→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 28→    ) {
 29→        node
 30→            .takeIf { node.elementType == PROPERTY }
 31→            ?.let { property -> visitProperty(property, emit) }
 32→    }
 33→
 34→    private fun visitProperty(
 35→        property: ASTNode,
 36→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 37→    ) {
 38→        property
 39→            .findChildByType(IDENTIFIER)
 40→            ?.let { identifier ->
 41→                when {
 42→                    property.hasCustomGetter() -> {
 43→                        // Can not reliably determine whether the value is immutable or not
 44→                    }
 45→                    property.isBackingProperty() -> {
 46→                        visitBackingProperty(identifier, emit)
 47→                    }
 48→                    property.hasConstModifier() ||
 49→                        property.isTopLevelValue() ||
 50→                        property.isObjectValue() -> {
 51→                        visitConstProperty(identifier, emit)
 52→                    }
 53→                    else -> {
 54→                        visitNonConstProperty(identifier, emit)
 55→                    }
 56→                }
 57→            }
 58→    }
 59→
 60→    private fun visitBackingProperty(
 61→        identifier: ASTNode,
 62→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 63→    ) {
 64→        identifier
 65→            .text
 66→            .takeUnless { it.matches(BACKING_PROPERTY_LOWER_CAMEL_CASE_REGEXP) }
 67→            ?.let {
 68→                emit(identifier.startOffset, "Backing property name should start with underscore followed by lower camel case", false)
 69→            }
 70→    }
 71→
 72→    private fun visitConstProperty(
 73→        identifier: ASTNode,
 74→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 75→    ) {
 76→        identifier
 77→            .text
 78→            .takeUnless { it.matches(SCREAMING_SNAKE_CASE_REGEXP) }
 79→            ?.let {
 80→                emit(identifier.startOffset, "Property name should use the screaming snake case notation when the value can not be changed", false)
 81→            }
 82→    }
 83→
 84→    private fun visitNonConstProperty(
 85→        identifier: ASTNode,
 86→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 87→    ) {
 88→        identifier
 89→            .text
 90→            .takeUnless { it.matches(LOWER_CAMEL_CASE_REGEXP) }
 91→            ?.let {
 92→                emit(identifier.startOffset, "Property name should start with a lowercase letter and use camel case", false)
 93→            }
 94→    }
 95→
 96→    private fun ASTNode.hasCustomGetter() =
 97→        findChildByType(PROPERTY_ACCESSOR)
 98→            ?.firstChildNode
 99→            ?.text == "get"
100→
101→    private fun ASTNode.hasConstModifier() =
102→        hasModifier(CONST_KEYWORD)
103→
104→    private fun ASTNode.hasModifier(iElementType: IElementType) =
105→        findChildByType(MODIFIER_LIST)
106→            ?.children()
107→            .orEmpty()
108→            .any { it.elementType == iElementType }
109→
110→    private fun ASTNode.isTopLevelValue() =
111→        treeParent.elementType == FILE && containsValKeyword()
112→
113→    private fun ASTNode.containsValKeyword() =
114→        children().any { it.elementType == VAL_KEYWORD }
115→
116→    private fun ASTNode.isObjectValue() =
117→        treeParent.elementType == CLASS_BODY &&
118→            treeParent?.treeParent?.elementType == OBJECT_DECLARATION &&
119→            containsValKeyword() &&
120→            !hasModifier(OVERRIDE_KEYWORD)
121→
122→    private fun ASTNode.isBackingProperty() =
123→        takeIf { hasModifier(PRIVATE_KEYWORD) }
124→            ?.findChildByType(IDENTIFIER)
125→            ?.takeIf { it.text.startsWith("_") }
126→            ?.let { identifier ->
127→                this.hasPublicProperty(identifier.text.removePrefix("_"))
128→            }
129→            ?: false
130→
131→    private fun ASTNode.hasPublicProperty(identifier: String) =
132→        treeParent
133→            .children()
134→            .filter { it.elementType == PROPERTY }
135→            .mapNotNull { it.findChildByType(IDENTIFIER) }
136→            .any { it.text == identifier }
137→
138→    private companion object {
139→        val LOWER_CAMEL_CASE_REGEXP = Regex("[a-z][a-zA-Z0-9]*")
140→        val SCREAMING_SNAKE_CASE_REGEXP = Regex("[A-Z][_A-Z0-9]*")
141→        val BACKING_PROPERTY_LOWER_CAMEL_CASE_REGEXP = Regex("_[a-z][a-zA-Z0-9]*")
142→    }
143→}
